+  r = await hookPostEdit({ filePath: 'src/c.ts', success: false, agent: 'coder', errorMessage: 'TypeError: undefined' });
+  check('Calculates accuracy', Math.abs(r.routingAccuracy - 0.67) < 0.1, `${(r.routingAccuracy * 100).toFixed(0)}%`);
+
